// Caso: Búsqueda binaria (clásico) | Nivel: Intermedio | Categoría: Clásicos
int solve(const long long* arr, int n, long long target){
  int lo=0, hi=n-1;
  while(lo<=hi){
    int mid=(lo+hi)/2;
    long long v=arr[mid];
    if(v==target) return mid;
    if(v<target) lo=mid+1; else hi=mid-1;
  }
  return -1;
}

