// Caso: Validar RUT chileno | Nivel: Intermedio | Categoría: Validación
#include <ctype.h>
#include <string.h>

int solve(const char* rut){
  if(!rut) return 0;

  char clean[64];
  int n=0;
  for(int i=0; rut[i] && n < 63; i++){
    char c = rut[i];
    if(c=='.' || c=='-' || isspace((unsigned char)c)) continue;
    clean[n++] = (char)toupper((unsigned char)c);
  }
  clean[n]='\0';
  if(n < 2) return 0;

  char dv = clean[n-1];
  clean[n-1] = '\0'; // body

  for(int i=0; clean[i]; i++){
    if(!isdigit((unsigned char)clean[i])) return 0;
  }

  int sum=0, mul=2;
  for(int i=(int)strlen(clean)-1; i>=0; i--){
    int d = clean[i]-'0';
    sum += d * mul;
    mul = (mul==7)?2:(mul+1);
  }

  int mod = 11 - (sum % 11);
  char dvCalc = (mod==11)?'0':(mod==10)?'K':(char)('0'+mod);
  return dv==dvCalc;
}

