// C0661 · Retry + backoff + timeout (Intermedio, Resiliencia)
#include <time.h>
#include <stdlib.h>

static void sleep_ms(int ms){
  struct timespec ts;
  ts.tv_sec = ms / 1000;
  ts.tv_nsec = (ms % 1000) * 1000000L;
  nanosleep(&ts, NULL);
}

int solve(int maxRetries){
  int attempt = 0;
  int delay = 200;
  while(1){
    attempt++;
    // doWork(): falla 70% (demo)
    double r = (double)rand() / (double)RAND_MAX;
    if(r >= 0.7) return 0; // ok
    if(attempt >= maxRetries) return 1; // fail
    sleep_ms(delay);
    delay = delay * 2;
    if(delay > 5000) delay = 5000;
  }
}

