// C0665 · Binary search (iterativo) (Básico, Algoritmos)
#include <stddef.h>

int solve(const int *arr, size_t n, int target){
  size_t lo = 0, hi = (n==0) ? 0 : (n-1);
  while(n > 0 && lo <= hi){
    size_t mid = lo + (hi - lo) / 2;
    int v = arr[mid];
    if(v == target) return (int)mid;
    if(v < target) lo = mid + 1;
    else {
      if(mid == 0) break;
      hi = mid - 1;
    }
  }
  return -1;
}

snippets.C0666:
// C0666 · Merge sort (Intermedio, Algoritmos)
#include <stdlib.h>
#include <string.h>

static void merge(int *a, int *tmp, size_t lo, size_t mid, size_t hi){
  size_t i=lo, j=mid, k=lo;
  while(i<mid && j<hi){
    if(a[i] <= a[j]) tmp[k++] = a[i++];
    else tmp[k++] = a[j++];
  }
  while(i<mid) tmp[k++] = a[i++];
  while(j<hi) tmp[k++] = a[j++];
  memcpy(a+lo, tmp+lo, (hi-lo)*sizeof(int));
}

static void msort(int *a, int *tmp, size_t lo, size_t hi){
  if(hi - lo <= 1) return;
  size_t mid = lo + (hi-lo)/2;
  msort(a,tmp,lo,mid);
  msort(a,tmp,mid,hi);
  merge(a,tmp,lo,mid,hi);
}

void solve(int *arr, size_t n){
  int *tmp = (int*)malloc(n*sizeof(int));
  if(!tmp) return;
  msort(arr,tmp,0,n);
  free(tmp);
}

snippets.C0667:
// C0667 · BFS/DFS (grafo) (Intermedio, Algoritmos)
/*
  BFS/DFS en C suele requerir estructuras (cola/pila) y representación del grafo.
  Para comparar visualmente: define lista de adyacencia y recorre.

  Este ejemplo asume:
  - vertices 0..(n-1)
  - adjacency list: int** adj; int* deg;
*/
#include <stdlib.h>

void bfs(int n, int **adj, int *deg, int start, int *out, int *outLen){
  int *q = (int*)malloc(n*sizeof(int));
  int head=0, tail=0;
  char *seen = (char*)calloc(n,1);
  *outLen = 0;

  q[tail++] = start; seen[start]=1;
  while(head < tail){
    int v = q[head++];
    out[(*outLen)++] = v;
    for(int i=0;i<deg[v];i++){
      int nb = adj[v][i];
      if(!seen[nb]){ seen[nb]=1; q[tail++] = nb; }
    }
  }
  free(q); free(seen);
}

void dfs_rec(int n, int **adj, int *deg, int v, char *seen, int *out, int *outLen){
  seen[v]=1; out[(*outLen)++] = v;
  for(int i=0;i<deg[v];i++){
    int nb = adj[v][i];
    if(!seen[nb]) dfs_rec(n, adj, deg, nb, seen, out, outLen);
  }
}

void dfs(int n, int **adj, int *deg, int start, int *out, int *outLen){
  char *seen = (char*)calloc(n,1);
  *outLen = 0;
  dfs_rec(n, adj, deg, start, seen, out, outLen);
  free(seen);
}

snippets.C0669:
// C0669 · LRU cache (Intermedio, Algoritmos)
/*
  LRU en C "bien" requiere lista doble + hash map.
  Para estudiar: se muestra una versión simple O(n) en búsqueda de clave
  (sirve para ver el concepto, no para performance).
*/
#include <string.h>

typedef struct {
  const char* key;
  int value;
} Entry;

typedef struct {
  int cap;
  int size;
  Entry entries[128];  // ejemplo fijo
} LRU;

void lru_init(LRU* lru, int cap){ lru->cap=cap; lru->size=0; }

static int find(LRU* lru, const char* key){
  for(int i=0;i<lru->size;i++){
    if(strcmp(lru->entries[i].key, key)==0) return i;
  }
  return -1;
}

static void move_to_end(LRU* lru, int idx){
  Entry e = lru->entries[idx];
  for(int i=idx;i<lru->size-1;i++) lru->entries[i]=lru->entries[i+1];
  lru->entries[lru->size-1] = e;
}

int lru_get(LRU* lru, const char* key, int* out){
  int idx = find(lru,key);
  if(idx<0) return 0;
  *out = lru->entries[idx].value;
  move_to_end(lru, idx);
  return 1;
}

void lru_put(LRU* lru, const char* key, int value){
  int idx = find(lru,key);
  if(idx>=0){
    lru->entries[idx].value = value;
    move_to_end(lru, idx);
    return;
  }
  if(lru->size < lru->cap){
    lru->entries[lru->size++] = (Entry){ key, value };
    return;
  }
  // evict oldest (index 0)
  for(int i=0;i<lru->cap-1;i++) lru->entries[i]=lru->entries[i+1];
  lru->entries[lru->cap-1] = (Entry){ key, value };
}

