// C0680 · Uso de teclado (keydown/atajos) (Intermedio, UI/Entrada)
// C: lectura por stdin (requiere Enter). Para raw mode: termios/WinAPI.
#include <stdio.h>
#include <ctype.h>

int solve(void){
  printf("Escribe una tecla y Enter (w/a/s/d, q):\n");
  int ch;
  while((ch = getchar()) != EOF){
    if(ch=='\n' || ch=='\r') continue;
    ch = tolower(ch);
    if(ch=='q') break;
    if(ch=='w') puts("Mover: arriba");
    if(ch=='s') puts("Mover: abajo");
    if(ch=='a') puts("Mover: izquierda");
    if(ch=='d') puts("Mover: derecha");
  }
  return 0;
}

