// C0682 · Despliegue de hora activa (Básico, UI/Tiempo)
#include <stdio.h>
#include <time.h>
#ifdef _WIN32
#include <windows.h>
#define SLEEP1() Sleep(1000)
#else
#include <unistd.h>
#define SLEEP1() sleep(1)
#endif

int solve(){
  while(1){
    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    printf("\r%02d:%02d:%02d", tm->tm_hour, tm->tm_min, tm->tm_sec);
    fflush(stdout);
    SLEEP1();
  }
  return 0;
}
